  void salvar(String nome, url, int index) {
    if (_key.currentState.validate()) {
      // Sem erros na validação
      _key.currentState.save();
      salvarLista(nome, url, index);
      Navigator.pop(context);  
      setState(() {
        _validate = false;
      });                    
    } else {
      // erro de validação
      setState(() {
        _validate = true;
      });
    }
  }

