  }

  Widget _buildSearchField() {
    return Container(
      decoration: BoxDecoration(
        border: Border.all(color: Style.Colors.clickColor, width: 1),
        borderRadius: BorderRadius.circular(5.0),
      ),
      padding: EdgeInsets.all(5),
      width: MediaQuery.of(context).size.width - 20,
      child: Text(
        searchQuery,
        style: TextStyle(color: Style.Colors.fontColor),
      ),
    );
  }

  List<Widget> _buildActions() {
    if (!load) {
      return <Widget>[
        IconButton(
          focusColor: Style.Colors.noColor,
          icon: Icon(Icons.edit),
          onPressed: () {
            setState(() {
              load = true;
            });
          },
        ),
      ];
    } else {
      return <Widget>[
        IconButton(
          focusColor: Style.Colors.noColor,
          icon: Icon(Icons.search),
          onPressed: () {
            setState(() {
              Search();
            });
          },
        ),
      ];
    }
  }


  Future<void> Search() async {
    if (searchQuery.length > 1) {
      String api = Config.Configs.api + "/api/v1/video/search?q=" + searchQuery;
      Response response = await Dio().post(api);
      setState(() {
        load = false;
        data = response.data["data"];
      });
    }
  }

  GetNum(String type, String data) {
    if (type == "电影") {
      return Text("电影",
          style: TextStyle(
            color: Style.Colors.fontColor,
            fontSize: 10.0,
          ));
    } else {
      int num = data.split("\n").length;
      String sum;
      if (num < 10) {
        sum = "0" + num.toString();
      } else {
        sum = num.toString();
      }
      return Text(
        "第$sum集",
