/// Android TV generic buttons
enum Buttons { up, down, left, right, center, fastReverse, fastForward, playPause }

/// Android TV remote button key codes
extension KeyCodes on Buttons {
  int? get code {
    switch (this) {
      case Buttons.up:
        return 19;
      case Buttons.down:
        return 20;
      case Buttons.left:
        return 21;
      case Buttons.right:
        return 22;
      case Buttons.center:
        return 23;
      case Buttons.fastReverse:
        return 89;
      case Buttons.fastForward:
        return 90;
      case Buttons.playPause:
        return 85;
      default:
        return null;
    }
  }
}

/// Keyboard supports 2 different intput modes - alphabetical and numerical
enum KeyboardMode { alphabetical, numerical }

/// Key UI elements
class CustomKeyboardSymbol extends StatefulWidget {
  final String symbol;
  final Function onTap;
  final FocusNode? focusNode;
  final double keySize;

  const CustomKeyboardSymbol({
    super.key,
    required this.symbol,
    required this.onTap,
    this.focusNode,
    required this.keySize,
  });

  @override
  State<StatefulWidget> createState() {
    return _CustomKeyboardSymbolState();
  }
}

class _CustomKeyboardSymbolState extends State<CustomKeyboardSymbol> {
  bool _isFocused = false;

  @override
  Widget build(BuildContext context) {
    return InkWell(
      focusNode: widget.focusNode,
      child: AnimatedOpacity(
        opacity: _isFocused ? 1 : 0.4,
        duration: const Duration(milliseconds: 200),
        child: DecoratedBox(
          decoration: BoxDecoration(
            color: Colors.grey.shade900,
            borderRadius: BorderRadius.circular(3),
            boxShadow: const [
              BoxShadow(
                color: Colors.grey,
                blurRadius: 4,
              ),
            ],
          ),
          child: SizedBox(
            /// Set (max) width and height of the keyboard button
            width: widget.keySize > 80 ? 80 : widget.keySize,
            height: widget.keySize > 50 ? 50 : widget.keySize,
            child: Center(
              child: Text(
                widget.symbol.toUpperCase(),
                style: const TextStyle(
                  fontWeight: FontWeight.bold,
                  color: Colors.white,
                ),
              ),
            ),
          ),
        ),
      ),
      onTap: () => widget.onTap(),
      onFocusChange: (isFocused) => setState(() => _isFocused = isFocused),
    );
  }
}

class SearchScreen extends StatefulWidget {
  const SearchScreen({super.key});

  @override
  State<StatefulWidget> createState() {
    return _SearchScreenState();
  }
}

class _SearchScreenState extends State<SearchScreen> {
  /// Controller is "manually" updated
  final _searchTermController = TextEditingController();

  /// Set of letters
  static const _alphabetical = {
    'a',
    'b',
    'c',
    'd',
    'e',
    'f',
    'g',
    'h',
    'i',
    'j',
    'k',
    'l',
    'm',
    'n',
    'o',
    'p',
    'q',
    'r',
    's',
    't',
    'u',
    'v',
    'w',
    'x',
    'y',
    'z'
  };

  // Set of special characters
  static final _special = {
    for (int i = 0; i < 10; i++) i.toString(),
    '*',
    '-',
    '?',
    '/',
    '\$',
  };

  /// Required for listening to keyboard events.
  /// canRequestFocus must be set to false in order to prevent loss of button focus
  final _keyboardListenerFocusNode = FocusNode(canRequestFocus: false);

  /// Left-most button, if right end is reached this gets focused
  final _leftMostFocusNode = FocusNode();

  /// Right-most button, if left end is reached this gets focused
  final _rightMostFocusNode = FocusNode();

  /// StreamController object used to propagate keyboard mode changes
  final _modeController = StreamController<KeyboardMode>.broadcast();

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      body: Column(
        children: [
          DecoratedBox(
            decoration: const BoxDecoration(
              border: Border(
                bottom: BorderSide(
                  color: Colors.grey,
                  width: 0.2,
                ),
              ),
            ),
            child: Padding(
              padding: const EdgeInsets.all(12),
              child: Column(
                mainAxisSize: MainAxisSize.min,
                children: [
                  TextField(
                    enabled: false,
                    controller: _searchTermController,
                    decoration: const InputDecoration(
                      hintText: 'Enter your search term',
                    ),
                  ),
                  Padding(
                    padding: const EdgeInsets.only(top: 10),
                    child: RawKeyboardListener(
                      focusNode: _keyboardListenerFocusNode,
                      child: StreamBuilder(
                        stream: _modeController.stream,
                        initialData: KeyboardMode.alphabetical,
                        builder: (context, mode) {
                          final maxNumberOfKeys = _alphabetical.length > _special.length ? _alphabetical : _special;
                          final keySize = MediaQuery.of(context).size.width / maxNumberOfKeys.length - 22;
                          return Row(
                            mainAxisAlignment: MainAxisAlignment.center,
                            children: [
                              // Keyboard mode
                              CustomKeyboardSymbol(
                                focusNode: _leftMostFocusNode,
                                symbol: mode.data == KeyboardMode.alphabetical ? '123' : 'ABC',
                                keySize: keySize,
                                onTap: () {
                                  _modeController.add(
                                    mode.data == KeyboardMode.alphabetical ? KeyboardMode.numerical : KeyboardMode.alphabetical,
                                  );
                                },
                              ),
                              const SizedBox(width: 8),
                              // Empty space
                              CustomKeyboardSymbol(
                                symbol: '⎵',
                                keySize: keySize,
                                onTap: () {
                                  _searchTermController.text = _searchTermController.text + ' ';
                                },
                              ),
                              const SizedBox(width: 8),
                              for (var key in mode.data == KeyboardMode.alphabetical ? _alphabetical : _special)
                                Padding(
                                  padding: const EdgeInsets.only(right: 8),
                                  child: CustomKeyboardSymbol(
                                    symbol: key,
                                    keySize: keySize,
                                    onTap: () {
                                      _searchTermController.text = _searchTermController.text + key.toUpperCase();
                                    },
                                  ),
                                ),
                              // Delete
                              CustomKeyboardSymbol(
                                symbol: '⌫',
                                keySize: keySize,
                                onTap: () {
                                  if (_searchTermController.text.isNotEmpty) {
                                    String removeLast(String input) => input.substring(0, _searchTermController.text.length - 1);
                                    _searchTermController.text = removeLast(_searchTermController.text);
                                  }
                                },
                              ),
                              const SizedBox(width: 8),
                              // "Search" button
                              CustomKeyboardSymbol(
                                focusNode: _rightMostFocusNode,
                                symbol: '🔍',
                                keySize: keySize,
                                onTap: () {
                                  // TODO: Add your "search" function here
                                },
                              ),
                            ],
                          );
                        },
                      ),
                      onKey: (key) {
                        // Listen for keyboard input events, enables moving key focus from one side to the other
                        if (key.runtimeType == RawKeyDownEvent) {
                          final keyData = key.data.toString();
                          bool isCode(int code) => keyData.contains('keyCode: $code');
                          final leftKey = isCode(Buttons.left.code!) || isCode(123);
                          final rightKey = isCode(Buttons.right.code!) || isCode(124);
                          if (leftKey && _leftMostFocusNode.hasFocus) {
                            _rightMostFocusNode.requestFocus();
                          } else if (rightKey && _rightMostFocusNode.hasFocus) {
                            _leftMostFocusNode.requestFocus();
                          }
                        }
                      },
                    ),
                  ),
                ],
              ),
            ),
          ),
        ],
      ),
    );
  }

  @override
  void dispose() {
    _keyboardListenerFocusNode.dispose();
    _leftMostFocusNode.dispose();
    _rightMostFocusNode.dispose();
    _modeController.close();
    _searchTermController.dispose();
    super.dispose();
  }
}
