/// * @desc The class that creates the keyboard
class Keyboard extends StatelessWidget {
  const Keyboard({Key key, this.onTextInput, this.onBackspace})
      : super(key: key);

  final ValueSetter<String> onTextInput;
  final VoidCallback onBackspace;
  void _textInputHandler(String text) => onTextInput?.call(text);
  void _backspaceHandler() => onBackspace?.call();

  /// * @desc The main widget of the class
  /// * Widget renders keyboard rows
  @override
  Widget build(BuildContext context) {
    return Container(
      width: MediaQuery.of(context).size.width * 0.5,
      height: MediaQuery.of(context).size.height * 0.35,
      color: Colors.white,
      child: Column(
        children: [
          _buildRowOne(),
          _buildRowTwo(),
          _buildRowThree(),
          _buildRowFour(),
        ],
      ),
    );
  }

  /// * First row of the keyboard
  Expanded _buildRowOne() {
    return Expanded(
        child: Row(
      children: [
        TextKey(
          text: '1',
          onTextInput: _textInputHandler,
        ),
        TextKey(
          text: '2',
          onTextInput: _textInputHandler,
        ),
        TextKey(
          text: '3',
          onTextInput: _textInputHandler,
        )
      ],
    ));
  }

  /// * Second row of the keyboard
  Expanded _buildRowTwo() {
    return Expanded(
        child: Row(
      children: [
        TextKey(
          text: '4',
          onTextInput: _textInputHandler,
        ),
        TextKey(
          text: '5',
          onTextInput: _textInputHandler,
        ),
        TextKey(
          text: '6',
          onTextInput: _textInputHandler,
        )
      ],
    ));
  }

  /// * Third row of the keyboard
  _buildRowThree() {
    return Expanded(
        child: Row(
      children: [
        TextKey(
          text: '7',
          onTextInput: _textInputHandler,
        ),
        TextKey(
          text: '8',
          onTextInput: _textInputHandler,
        ),
        TextKey(
          text: '9',
          onTextInput: _textInputHandler,
        )
      ],
    ));
  }

  /// * Fourth row of the keyboard
  _buildRowFour() {
    return Expanded(
        child: Row(
      children: [
        TextKey(
          text: '.',
          onTextInput: _textInputHandler,
        ),
        TextKey(
          text: ':',
          onTextInput: _textInputHandler,
        ),
        TextKey(
          text: '0',
          onTextInput: _textInputHandler,
        ),
        BackspaceKey(
          onBackspace: _backspaceHandler,
        )
      ],
    ));
  }
}
