    this.autocorrect = false,
    this.inputType = TextInputType.text,
    required this.inputController,
    this.onDownPressCallback,
    this.onUpPressCallback,
    this.onRightPressCallback,
    this.onFocusedCallback,
    required this.onSubmitCallback,
    required this.placeholder,
    required this.onInputChange(value),
    Key? key
  }) : super(key: key);

  @override
  State<TvInputField> createState() => _TvInputFieldState();
}

class _TvInputFieldState extends State<TvInputField> {
  bool _focused = false;
  bool _selected = false;
  final widgetInputFocusNode = FocusNode();
  final widgetButtonFocusNode = FocusNode();

  buildButtonText(String text, bool obscure) {
    String newString = text;
    if(obscure) {
      newString = '';
      for (var i = 0; i < text.length; i++) {
        newString += '*';
      }
    }

    return newString;
  }

  buildChild() {
    if(!_selected) {
      return InkWell(
        autofocus: widget.autofocus,
        focusNode: widgetButtonFocusNode,
        onFocusChange: (focusedValue) {
          setState(() {
            _focused = focusedValue;
          });
          if(widget.onRightPressCallback != null) {
            widget.onFocusedCallback!(focusedValue);
          }
        },
        onTap: () {
          setState(() {
            _selected = true;
            widgetInputFocusNode.requestFocus();
          });
        },
        child: AnimatedContainer(
          duration: const Duration(milliseconds: 200),
          decoration: BoxDecoration(
            border: Border.all(
              color: _focused ? Colors.pink : Colors.white,
              width: 1.5
            ),
          ),
          child: Center(
            child: Text(
              widget.inputController.text != '' ? buildButtonText(widget.inputController.text, widget.obscureText) : widget.placeholder,
              style: TextStyle(
                color: widget.inputController.text != '' ? Colors.pink : Colors.grey[700],
                fontWeight: FontWeight.bold
              )
            ),
          ),
        ),
      );
    } else {
      return Focus(
        canRequestFocus: false,
        onKey: (node, event) {
          if(event is RawKeyDownEvent) {
            switch (event.logicalKey.keyLabel) {
              case 'Arrow Down':
                if(widget.onDownPressCallback != null) {
                  setState(() {
                    _selected = false;
                    _focused = false;
                  });
                  widget.onDownPressCallback!();
                }
                return KeyEventResult.handled;
              case 'Arrow Up':
                if(widget.onUpPressCallback != null) {
                  setState(() {
                    _selected = false;
                    _focused = false;
                  });
                  widget.onUpPressCallback!();
                }
                return KeyEventResult.handled;
              case 'Arrow Right':
                if(widget.onRightPressCallback != null) {
                  setState(() {
                    _selected = false;
                    _focused = false;
                  });
                  widget.onRightPressCallback!();
                }
                return KeyEventResult.handled;
            }
          }
          return KeyEventResult.ignored;
        },
        child: TextField(
          autocorrect: widget.autocorrect,
          controller: widget.inputController,
          focusNode: widgetInputFocusNode,
          obscureText: widget.obscureText,
          cursorColor: Colors.pink,
          keyboardType: widget.inputType,
          style: TextStyle(
            color: Colors.pink,
          ),
          onChanged: (value) {
            widget.onInputChange(value);
          },
          textInputAction: TextInputAction.next,
          onSubmitted: (value) {
            setState(() {
              _selected = false;
              _focused = false;
            });
            widget.onSubmitCallback();
          },
          decoration: InputDecoration(
            focusedBorder: const OutlineInputBorder(
              borderSide: BorderSide.none
            ),
            filled: true,
            fillColor: Colors.black
          ),
        )
      );
    }
  }

  void selectInputField() {
    setState(() {
      _selected = true;
      widgetInputFocusNode.requestFocus();
    });
  }

  @override
  Widget build(BuildContext context) {
    return AnimatedContainer(
      duration: const Duration(milliseconds: 200),
      child: buildChild(),
      decoration: BoxDecoration(
        color: Colors.black,
        border: Border.all(
          color: _selected ? Colors.pink : Colors.black
        )
      )
    );
  }
}
