I'm late to this, but yesterday I ran into the same issue where my app has 3 text fields and a button and when a text field is focused you can't go back and change the focus to another text field text or button, but I found a "Solution".

This is more of a workaround, but I noticed that I didn't need the text field to be focused if the user hits the back button to remove the keyboard, so I found a listener keyboard here by **abdullah-alamodi**:
https://stackoverflow.com/questions/48085203/flutter-keyboard-listen-on-hide-and-show

and wrapped my text fields with a container to show which one is focused and for each container I created a focus node and did the same for each text field.

Below you will find the code and an example video feel free to modify/improve it and don't forget to post it here 😉.

- **_KeyboardVisibilityListenerState**

```
import "package:flutter/material.dart";

class KeyboardVisibilityListener extends StatefulWidget {
  final Widget child;
  final void Function(
      bool isKeyboardVisible,
      ) listener;

  const KeyboardVisibilityListener({
    Key? key,
    required this.child,
    required this.listener,
  }) : super(key: key);

  @override
  _KeyboardVisibilityListenerState createState() =>
      _KeyboardVisibilityListenerState();
}

class _KeyboardVisibilityListenerState extends State<KeyboardVisibilityListener>
    with WidgetsBindingObserver {
  var _isKeyboardVisible = false;

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance?.addObserver(this);
  }

  @override
  void dispose() {
    WidgetsBinding.instance?.removeObserver(this);
    super.dispose();
  }

  @override
  void didChangeMetrics() {
    final bottomInset = WidgetsBinding.instance!.window.viewInsets.bottom;
    final newValue = bottomInset > 0.0;
    if (newValue != _isKeyboardVisible) {
      _isKeyboardVisible = newValue;
      widget.listener(_isKeyboardVisible);
    }
  }

  @override
  Widget build(BuildContext context) => widget.child;
}
