import "package:flutter/material.dart";

class Home extends StatefulWidget {
  const Home({Key? key}) : super(key: key);

  @override
  State<Home> createState() => _HomeState();
}

class _HomeState extends State<Home> {
  // Containers and TextFields FocusNodes
  final FocusNode _usernameNode = FocusNode();
  final FocusNode _passwordNode = FocusNode();
  final FocusNode _hintNode = FocusNode();
  final FocusNode _usernameTextNode = FocusNode();
  final FocusNode _passwordTextNode = FocusNode();
  final FocusNode _hintTextNode = FocusNode();
  final FocusNode _buttonNode = FocusNode();

  // Variable to stock the selected FocusNode
  FocusNode _selectedNode = FocusNode();

  // To detect if this is the first load or not, since the context is initialized in build
  bool _firstLoad = true;

  // On first load, always Focus on the username container
  void _setFirstNode() {
    FocusScope.of(context).requestFocus(_usernameNode);
    setState(() {});
  }

  // Change the focus to another FocusNode
  void _changeNode(BuildContext context, FocusNode node) {
    FocusScope.of(context).requestFocus(node);
    setState(() {
      _firstLoad = false;
    });
  }

  @override
  void initState() {
    super.initState();

    // Change the _selectedNode to have the FocusNode that has focus
    _usernameNode.addListener(() {
      if (_usernameNode.hasFocus) {
        setState(() {
          _selectedNode = _usernameNode;
        });
      }
    });
    _passwordNode.addListener(() {
      if (_passwordNode.hasFocus) {
        setState(() {
          _selectedNode = _passwordNode;
        });
      }
    });
    _hintNode.addListener(() {
      if (_hintNode.hasFocus) {
        setState(() {
          _selectedNode = _hintNode;
        });
      }
    });
    _buttonNode.addListener(() {
      if (_buttonNode.hasFocus) {
        setState(() {
          _selectedNode = _buttonNode;
        });
      }
    });
  }

  @override
  Widget build(BuildContext context) {
    // set focus on Username if it"s the first loading
    if (_firstLoad) {
      _setFirstNode();
    }

    // When keyboard is closed, change focus to what is in _selectedNode
    return KeyboardVisibilityListener(
      listener: (isKeyboardVisible) {
        if (!isKeyboardVisible) {
          FocusScope.of(context).unfocus();
          if (_selectedNode == _usernameNode) {
            _changeNode(context, _usernameNode);
          } else if (_selectedNode == _passwordNode) {
            _changeNode(context, _passwordNode);
          } else if (_selectedNode == _hintNode) {
            _changeNode(context, _hintNode);
          } else {
            _changeNode(context, _buttonNode);
          }
